export function $(selector,context=document){if(typeof context==='string'){context=document.querySelector(context);}return context ? context.querySelector(selector): null;}export function $$(selector,context=document){if(typeof context==='string'){context=document.querySelector(context);}return context ? Array.from(context.querySelectorAll(selector)): [];}export function on(elements,event,handler,options={}){if(!Array.isArray(elements)){elements=[elements];}elements.forEach(el=>{if(el){el.addEventListener(event,handler,options);}});}export function off(elements,event,handler){if(!Array.isArray(elements)){elements=[elements];}elements.forEach(el=>{if(el){el.removeEventListener(event,handler);}});}export function createElement(tag,attributes={},content=null){const el=document.createElement(tag);Object.entries(attributes).forEach(([key,value])=>{if(key==='className'){el.className=value;}else if(key==='dataset'){Object.entries(value).forEach(([k,v])=>{el.dataset[k]=v;});}else if(key==='style'){Object.assign(el.style,value);}else if(key.startsWith('on')){const event=key.slice(2).toLowerCase();el.addEventListener(event,value);}else{el.setAttribute(key,value);}});if(content){if(typeof content==='string'){el.innerHTML=content;}else if(content instanceof Element){el.appendChild(content);}}return el;}export function toggleClass(el,className,force){if(!el)return;el.classList.toggle(className,force);}export function addClass(el,...classNames){if(!el)return;classNames.forEach(name=>{if(name)el.classList.add(name);});}export function removeClass(el,...classNames){if(!el)return;classNames.forEach(name=>{if(name)el.classList.remove(name);});}export function hasClass(el,className){return el ? el.classList.contains(className): false;}export function closest(el,selector){return el ? el.closest(selector): null;}export function matches(el,selector){return el ? el.matches(selector): false;}export function delegate(parent,selector,event,handler,options={}){on(parent,event,(e)=>{const target=e.target.closest(selector);if(target&&parent.contains(target)){handler.call(target,e);}},options);}export function ready(callback){if(document.readyState!=='loading'){callback();}else{document.addEventListener('DOMContentLoaded',callback);}}export function waitForElement(selector,context=document,timeout=5000){return new Promise((resolve,reject)=>{const el=context.querySelector(selector);if(el){resolve(el);return;}const observer=new MutationObserver(()=>{const found=context.querySelector(selector);if(found){observer.disconnect();resolve(found);}});observer.observe(context,{childList: true,subtree: true});if(timeout>0){setTimeout(()=>{observer.disconnect();reject(new Error(`Timeout waiting for: ${selector}`));},timeout);}});}export function remove(el){if(el&&el.parentNode){el.parentNode.removeChild(el);}}export function empty(el){if(el){el.innerHTML='';}}export function show(el,display='block'){if(el){el.style.display=display;}}export function hide(el){if(el){el.style.display='none';}}export function isVisible(el){if(!el)return false;const style=window.getComputedStyle(el);return style.display!=='none'&&style.visibility!=='hidden'&&style.opacity!=='0';}export function getOffset(el){if(!el)return{top: 0,left: 0};const rect=el.getBoundingClientRect();return{top: rect.top+window.pageYOffset,left: rect.left+window.pageXOffset};}export function scrollIntoView(el,options={behavior: 'smooth',block: 'start'}){if(el){el.scrollIntoView(options);}}export function setAttributes(el,attributes){if(!el)return;Object.entries(attributes).forEach(([key,value])=>{if(key==='className'){el.className=value;}else if(key==='dataset'){Object.entries(value).forEach(([k,v])=>{el.dataset[k]=v;});}else if(key==='style'){Object.assign(el.style,value);}else{el.setAttribute(key,value);}});}export function getData(el,key){return el ? el.dataset[key]||null : null;}export function setData(el,key,value){if(el){el.dataset[key]=value;}}export const dom={$,$$,on,off,delegate,create: createElement,toggle: toggleClass,add: addClass,remove: removeClass,has: hasClass,closest,matches,ready,wait: waitForElement,remove,empty,show,hide,visible: isVisible,offset: getOffset,scroll: scrollIntoView,attrs: setAttributes,data:{get: getData,set: setData}};if(typeof window!=='undefined'){window.dom=dom;window.$=$;window.$$=$$;}